﻿// ============================================================
// 个人云数据存储 - Cloudflare Worker (含认证)
// ============================================================
import { HTML } from './html.js';
import { hashPassword, generateSalt, generateToken, DEFAULT_USERNAME, DEFAULT_PASSWORD } from './auth-utils.js';

const CATEGORIES = ["images", "novels", "documents", "stickies"];

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' }
  });
}

function error(msg, status = 400) {
  return json({ error: msg }, status);
}

function generateId() {
  return Date.now().toString(36) + Math.random().toString(36).substring(2, 10);
}

function estimateSize(item) {
  let size = 0;
  if (item.fileData) {
    const comma = item.fileData.indexOf(',');
    if (comma > 0) size = Math.round((item.fileData.length - comma - 1) * 0.75);
  }
  if (item.content) size += new TextEncoder().encode(item.content).length;
  return size;
}

// ============================================================
// Auth helpers
// ============================================================
async function getCredentials(env) {
  let creds = await env.PERSONAL_CLOUD_KV.get('auth:credentials', 'json');
  if (!creds) {
    const salt = generateSalt();
    const hash = await hashPassword(DEFAULT_PASSWORD, salt);
    creds = { username: DEFAULT_USERNAME, passwordHash: hash, salt };
    await env.PERSONAL_CLOUD_KV.put('auth:credentials', JSON.stringify(creds));
  }
  return creds;
}

async function validateToken(env, token) {
  if (!token) return false;
  const session = await env.PERSONAL_CLOUD_KV.get('auth:token:' + token, 'json');
  if (!session) return false;
  if (Date.now() > session.expires) {
    await env.PERSONAL_CLOUD_KV.delete('auth:token:' + token);
    return false;
  }
  return true;
}

async function requireAuth(request, env) {
  const auth = request.headers.get('Authorization') || '';
  const token = auth.startsWith('Bearer ') ? auth.slice(7) : '';
  if (!(await validateToken(env, token))) {
    return error('未授权，请先登录', 401);
  }
  return null;
}

// ============================================================
// Existing helpers
// ============================================================
async function getStorageStats(env) {
  const all = await env.PERSONAL_CLOUD_KV.list({ prefix: 'item:' });
  const stats = { totalSize: 0, totalItems: 0, categories: {} };
  CATEGORIES.forEach(c => stats.categories[c] = { count: 0, size: 0 });
  for (const key of all.keys) {
    const val = await env.PERSONAL_CLOUD_KV.get(key.name, 'json');
    if (!val) continue;
    stats.totalItems++;
    const size = estimateSize(val);
    stats.totalSize += size;
    const cat = val.category;
    if (stats.categories[cat]) { stats.categories[cat].count++; stats.categories[cat].size += size; }
  }
  return stats;
}

async function listItems(env, category) {
  const prefix = category ? 'item:' + category + ':' : 'item:';
  const result = await env.PERSONAL_CLOUD_KV.list({ prefix });
  const items = [];
  for (const key of result.keys) {
    const val = await env.PERSONAL_CLOUD_KV.get(key.name, 'json');
    if (val) items.push(val);
  }
  items.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
  return items;
}

async function getCounts(env) {
  const all = await env.PERSONAL_CLOUD_KV.list({ prefix: 'item:' });
  const counts = { all: 0 };
  CATEGORIES.forEach(c => counts[c] = 0);
  for (const key of all.keys) {
    counts.all++;
    const parts = key.name.split(':');
    if (parts.length >= 2) { const cat = parts[1]; if (counts[cat] !== undefined) counts[cat]++; }
  }
  return counts;
}

async function findItem(env, itemId) {
  for (const cat of CATEGORIES) {
    const item = await env.PERSONAL_CLOUD_KV.get('item:' + cat + ':' + itemId, 'json');
    if (item) return { item, key: 'item:' + cat + ':' + itemId };
  }
  return null;
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (request.method === 'OPTIONS') {
      return new Response(null, {
        status: 204,
        headers: {
          'Access-Control-Allow-Origin': '*',
          'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS',
          'Access-Control-Allow-Headers': 'Content-Type,Authorization'
        }
      });
    }

    // Serve frontend (no auth needed)
    if (path === '/' || path === '/index.html') {
      return new Response(HTML, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' }
      });
    }

    // ============================================================
    // Auth endpoints (no token needed)
    // ============================================================
    if (path === '/api/auth/login' && request.method === 'POST') {
      try {
        const body = await request.json();
        const creds = await getCredentials(env);
        const inputHash = await hashPassword(body.password || '', creds.salt);
        if (body.username === creds.username && inputHash === creds.passwordHash) {
          const token = generateToken();
          await env.PERSONAL_CLOUD_KV.put('auth:token:' + token, JSON.stringify({
            username: creds.username,
            createdAt: Date.now(),
            expires: Date.now() + 86400000 // 24h
          }));
          return json({ token, expires: Date.now() + 86400000, username: creds.username });
        }
        return error('用户名或密码错误', 401);
      } catch (e) { return error('请求格式错误'); }
    }

    // Check token
    if (path === '/api/auth/check' && request.method === 'GET') {
      const auth = request.headers.get('Authorization') || '';
      const token = auth.startsWith('Bearer ') ? auth.slice(7) : '';
      const valid = await validateToken(env, token);
      return json({ valid });
    }

    // ============================================================
    // Protected endpoints
    // ============================================================

    // Change credentials
    if (path === '/api/auth/change' && request.method === 'POST') {
      const authErr = await requireAuth(request, env);
      if (authErr) return authErr;
      try {
        const body = await request.json();
        const creds = await getCredentials(env);
        const inputHash = await hashPassword(body.currentPassword || '', creds.salt);
        if (inputHash !== creds.passwordHash) {
          return error('当前密码错误', 401);
        }
        const newSalt = generateSalt();
        const newHash = await hashPassword(body.newPassword || DEFAULT_PASSWORD, newSalt);
        const newCreds = {
          username: body.newUsername || creds.username,
          passwordHash: newHash,
          salt: newSalt
        };
        await env.PERSONAL_CLOUD_KV.put('auth:credentials', JSON.stringify(newCreds));
        return json({ success: true, username: newCreds.username });
      } catch (e) { return error('请求格式错误'); }
    }

    // Logout
    if (path === '/api/auth/logout' && request.method === 'POST') {
      const auth = request.headers.get('Authorization') || '';
      const token = auth.startsWith('Bearer ') ? auth.slice(7) : '';
      if (token) await env.PERSONAL_CLOUD_KV.delete('auth:token:' + token);
      return json({ success: true });
    }

    // Stats (protected)
    if (path === '/api/stats' && request.method === 'GET') {
      const authErr = await requireAuth(request, env);
      if (authErr) return authErr;
      return json(await getStorageStats(env));
    }

    // Items API (protected)
    if (path === '/api/items' || path === '/api/items/') {
      const authErr = await requireAuth(request, env);
      if (authErr) return authErr;

      if (request.method === 'GET') {
        if (url.searchParams.has('counts')) return json(await getCounts(env));
        return json(await listItems(env, url.searchParams.get('category') || null));
      }

      if (request.method === 'POST') {
        try {
          const body = await request.json();
          if (!body.title || !body.category) return error('标题和分类为必填项');
          if (!CATEGORIES.includes(body.category)) return error('无效的分类');
          const id = generateId();
          const now = new Date().toISOString();
          const item = {
            id, title: body.title, content: body.content || '', category: body.category,
            fileData: body.fileData || null, fileName: body.fileName || null,
            fileType: body.fileType || null, fileSize: body.fileSize || 0,
            createdAt: now, updatedAt: now
          };
          await env.PERSONAL_CLOUD_KV.put('item:' + item.category + ':' + id, JSON.stringify(item));
          return json(item, 201);
        } catch (e) { return error('请求格式错误: ' + e.message); }
      }
    }

    // Single item (protected)
    const match = path.match(/^\/api\/items\/([a-z0-9]+)$/);
    if (match) {
      const authErr = await requireAuth(request, env);
      if (authErr) return authErr;
      const itemId = match[1];

      if (request.method === 'GET') {
        const found = await findItem(env, itemId);
        return found ? json(found.item) : error('未找到', 404);
      }

      if (request.method === 'PUT') {
        try {
          const body = await request.json();
          const found = await findItem(env, itemId);
          if (!found) return error('未找到', 404);
          const existing = found.item;
          const nc = (body.category && CATEGORIES.includes(body.category)) ? body.category : existing.category;
          const updated = {
            ...existing,
            title: body.title !== undefined ? body.title : existing.title,
            content: body.content !== undefined ? body.content : existing.content,
            category: nc,
            fileData: body.fileData !== undefined ? body.fileData : existing.fileData,
            fileName: body.fileName !== undefined ? body.fileName : existing.fileName,
            fileType: body.fileType !== undefined ? body.fileType : existing.fileType,
            fileSize: body.fileSize !== undefined ? body.fileSize : existing.fileSize,
            updatedAt: new Date().toISOString()
          };
          const nk = 'item:' + nc + ':' + itemId;
          if (found.key !== nk) await env.PERSONAL_CLOUD_KV.delete(found.key);
          await env.PERSONAL_CLOUD_KV.put(nk, JSON.stringify(updated));
          return json(updated);
        } catch (e) { return error('请求格式错误'); }
      }

      if (request.method === 'DELETE') {
        const found = await findItem(env, itemId);
        if (!found) return error('未找到', 404);
        await env.PERSONAL_CLOUD_KV.delete(found.key);
        return json({ success: true });
      }
    }

    return error('Not Found', 404);
  }
};
